1	interface Item {
2	  type: string;
3	}
4	
5	interface QuoteStep {
6	  op: "quote";
7	  items: Item[];
8	}
9	
10	interface Customer {
11	  yearsWithMHPCO: number;
12	}
13	
14	interface Scenario {
15	  customer: Customer;
16	  steps: QuoteStep[];
17	}
18	
19	const COMPONENT_PREMIUM = 25;
20	const BLOCK_SIZE = 3;
21	const BLOCK_PREMIUM = 60;
22	
23	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
24	const PROCESSING_FEE = 5;
25	const ROUNDING_PRECISION = 6;
26	
27	const componentBasePremium = (count: number): number => {
28	  if (count === BLOCK_SIZE) return BLOCK_PREMIUM;
29	  return count * COMPONENT_PREMIUM;
30	};
31	
32	export const runScenario = (scenario: Scenario): { results: unknown[] } => {
33	  const results = scenario.steps.map((step) => {
34	    const runeCount = step.items.filter((item) => item.type === "rune").length;
35	    const base = componentBasePremium(runeCount);
36	    const withFirstInsurance = base + base * FIRST_INSURANCE_SURCHARGE_RATE;
37	    const premium = Math.ceil(
38	      Number((withFirstInsurance + PROCESSING_FEE).toFixed(ROUNDING_PRECISION)),
39	    );
40	    return { premium };
41	  });
42	  return { results };
43	};
